import React from 'react';
import { Container, ListGroup } from 'react-bootstrap';

const Publications = () => {
  const publications = [
    "Publication 1: Title and details",
    "Publication 2: Title and details",
    "Publication 3: Title and details",
  ];

  return (
    <Container id="publications" className="bg-light py-4">
      <h2>Publications</h2>
      <ListGroup>
        {publications.map((pub, index) => (
          <ListGroup.Item key={index}>{pub}</ListGroup.Item>
        ))}
      </ListGroup>
    </Container>
  );
};

export default Publications;
